function gridTotalHeight(grid) {
  let totalHeight = 0;
  let gap = 10;
  for (let i = 0; i < grid.rows; i++) {
    for (let j = 0; j < grid.columns; j++) {
      totalHeight += grid.items[i * grid.columns + j].height + gap;
    }
  }
  return totalHeight;
}

